import{_ as e,c as a,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Статистика токенов: Контроль затрат и анализ данных | Antigravity Manager","description":"Изучите функцию статистики токенов Antigravity. Узнайте, как извлекать данные токенов из ответов, анализировать потребление по моделям и учётным записям, а также использовать списки Top для поиска самых дорогих моделей и учётных записей, и устранять проблемы отсутствия статистики.","frontmatter":{"title":"Статистика токенов: Контроль затрат и анализ данных | Antigravity Manager","sidebarTitle":"Сразу увидите, кто самый дорогой","subtitle":"Статистика токенов: Контроль затрат и анализ данных","description":"Изучите функцию статистики токенов Antigravity. Узнайте, как извлекать данные токенов из ответов, анализировать потребление по моделям и учётным записям, а также использовать списки Top для поиска самых дорогих моделей и учётных записей, и устранять проблемы отсутствия статистики.","tags":["Token Stats","затраты","мониторинг","SQLite","статистика потребления"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":7},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}'),d={name:"ru/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function l(i,t,s,n,c,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="статистика-токенов-статистические-показатели-с-точки-зрения-затрат-и-интерпретация-графиков" tabindex="-1">Статистика токенов: Статистические показатели с точки зрения затрат и интерпретация графиков <a class="header-anchor" href="#статистика-токенов-статистические-показатели-с-точки-зрения-затрат-и-интерпретация-графиков" aria-label="Permalink to &quot;Статистика токенов: Статистические показатели с точки зрения затрат и интерпретация графиков&quot;">​</a></h1><p>Вы уже подключили клиентов к Antigravity Tools, но «кто на самом деле тратит деньги, что дорого, не стал ли вдруг скачок модели» обычно трудно судить по интуиции. В этом уроке будет рассказано только об одном: чётко объяснить показатели данных Token Stats, и научить быстро находить проблемы затрат с помощью графиков.</p><h2 id="что-вы-сможете-сделать-после-изучения" tabindex="-1">Что вы сможете сделать после изучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-изучения" aria-label="Permalink to &quot;Что вы сможете сделать после изучения&quot;">​</a></h2><ul><li>Понять, откуда берутся данные Token Stats (когда записываются, в каких случаях будут отсутствовать)</li><li>Переключать окно наблюдения по часам/дням/неделям, чтобы избежать ошибочного суждения из-за «только одного дня»</li><li>В видах «по моделям/по учётным записям» использовать графики тренда для поиска аномальных пиков</li><li>Использовать списки Top для фиксации самых дорогих моделей/учётных записей, а затем вернуться к журналам запросов для поиска причины</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><ul><li>Вы чувствуете, что вызовы стали дороже, но не знаете, изменилась ли модель, учётная запись, или внезапно увеличился объём за один день</li><li>Вы видели <code>X-Mapped-Model</code>, но не уверены, по какому стандарту модели считается статистика</li><li>В Token Stats иногда 0 или «нет данных», вы не знаете, это отсутствие трафика или отсутствие статистики</li></ul><h2 id="когда-использовать-этот-подход" tabindex="-1">Когда использовать этот подход <a class="header-anchor" href="#когда-использовать-этот-подход" aria-label="Permalink to &quot;Когда использовать этот подход&quot;">​</a></h2><ul><li>Вы хотите оптимизировать затраты: сначала количественно определить «кто самый дорогой»</li><li>Вы устраняете внезапные ограничения/аномалии: используйте момент времени пика в графике для сравнения с журналами запросов</li><li>Вы внесли изменения в конфигурацию маршрутизации моделей/управление квотами и хотите подтвердить, снизились ли затраты по ожиданиям</li></ul><h2 id="что-такое-token-stats" tabindex="-1">Что такое Token Stats? <a class="header-anchor" href="#что-такое-token-stats" aria-label="Permalink to &quot;Что такое Token Stats?&quot;">​</a></h2><p><strong>Token Stats</strong> — это страница локальной статистики потребления Antigravity Tools: после того, как прокси пересылает запрос, он пытается извлечь токены из поля <code>usage</code>/<code>usageMetadata</code> в ответе JSON, и записывает каждый запрос по учётной записи и модели в локальный SQLite (<code>token_stats.db</code>), а затем в UI суммирует и отображает по времени/моделям/учётным записям.</p><div class="info custom-block"><p class="custom-block-title">Сначала об одной ловушке</p><p>Показатель «модель» в Token Stats берётся из поля <code>model</code> вашего запроса (или из разбора пути <code>/v1beta/models/&lt;model&gt;</code> для Gemini), не равен <code>X-Mapped-Model</code> после маршрутизации.</p></div><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><ul><li>Вы уже выполнили один успешный вызов прокси (не останавливаетесь на <code>/healthz</code> для проверки работоспособности)</li><li>Ответы вашего вышестоящего провайдера содержат поля token, которые можно разобрать</li></ul><div class="tip custom-block"><p class="custom-block-title">Рекомендуется чтение вместе с другим уроком</p><p>Если вы используете маршрутизацию моделей, чтобы сопоставить <code>model</code> с другой физической моделью, сначала посмотрите <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/advanced/model-router/">Маршрутизация моделей: Пользовательские маппинги, приоритеты подстановок и предустановленные стратегии</a></strong>, затем вернитесь к этому уроку, чтобы понять «стандарт статистики» более интуитивно.</p></div><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Цепочка данных Token Stats делится на три сегмента:</p><ol><li>Промежуточное ПО прокси пытается извлечь потребление токенов из ответа (совместимо с <code>usage</code>/<code>usageMetadata</code>, потоковые запросы также разбираются)</li><li>Если одновременно получены <code>account_email + input_tokens + output_tokens</code>, записывается в локальный SQLite (<code>token_stats.db</code>)</li><li>UI через Tauri <code>invoke(get_token_stats_*)</code> вытягивает агрегированные данные и отображает по часам/дням/неделям</li></ol><h2 id="следуите-за-мнои" tabindex="-1">Следуйте за мной <a class="header-anchor" href="#следуите-за-мнои" aria-label="Permalink to &quot;Следуйте за мной&quot;">​</a></h2><h3 id="шаг-1-сначала-подтвердите-что-у-вас-есть-«трафик»" tabindex="-1">Шаг 1: Сначала подтвердите, что у вас есть «трафик» <a class="header-anchor" href="#шаг-1-сначала-подтвердите-что-у-вас-есть-«трафик»" aria-label="Permalink to &quot;Шаг 1: Сначала подтвердите, что у вас есть «трафик»&quot;">​</a></h3><p><strong>Почему</strong> Статистика Token Stats записывается от реальных запросов. Если вы только запустили прокси, но ни разу не отправляли запрос модели, страница будет отображать «нет данных».</p><p>Действие: используйте метод вызова, который вы уже подтвердили как работающий в <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Запуск локального обратного прокси и подключение первого клиента</a></strong>, отправьте 1-2 запроса.</p><p><strong>Вы должны увидеть</strong>: страница Token Stats меняется с «загрузка/нет данных» на графики или списки.</p><h3 id="шаг-2-выберите-правильное-окно-наблюдения-часы-дни-недели" tabindex="-1">Шаг 2: Выберите правильное окно наблюдения (часы/дни/недели) <a class="header-anchor" href="#шаг-2-выберите-правильное-окно-наблюдения-часы-дни-недели" aria-label="Permalink to &quot;Шаг 2: Выберите правильное окно наблюдения (часы/дни/недели)&quot;">​</a></h3><p><strong>Почему</strong> Одни и те же данные при разных окнах наблюдения выглядят совершенно по-разному. В UI три окна соответствуют разным диапазонам выборки:</p><ul><li>Часы: последние 24 часа</li><li>Дни: последние 7 дней</li><li>Недели: последние 4 недели (вид тренда будет агрегирован по последним 30 дням)</li></ul><p><strong>Вы должны увидеть</strong>: после переключения, горизонталь графика меняется (часы отображаются до «часа», дни до «день/месяц», недели до «год-Wнеделя»).</p><h3 id="шаг-3-сначала-посмотрите-на-итоговыи-обзор-чтобы-определить-«масштаб-затрат»" tabindex="-1">Шаг 3: Сначала посмотрите на итоговый обзор, чтобы определить «масштаб затрат» <a class="header-anchor" href="#шаг-3-сначала-посмотрите-на-итоговыи-обзор-чтобы-определить-«масштаб-затрат»" aria-label="Permalink to &quot;Шаг 3: Сначала посмотрите на итоговый обзор, чтобы определить «масштаб затрат»&quot;">​</a></h3><p><strong>Почему</strong> Карточка итогового обзора может сначала ответить на три вопроса: большой ли общий объём, аномальна ли доля ввода/вывода, и внезапно ли увеличилось количество учётных записей/моделей.</p><p>Обратите внимание на эти элементы:</p><ul><li>Всего токенов (<code>total_tokens</code>)</li><li>Токены ввода/вывода (<code>total_input_tokens</code> / <code>total_output_tokens</code>)</li><li>Количество активных учётных записей (<code>unique_accounts</code>)</li><li>Количество используемых моделей (UI напрямую использует длину списка «статистика по моделям»)</li></ul><p><strong>Вы должны увидеть</strong>: если «количество активных учётных записей» внезапно увеличилось, это обычно означает, что в короткое время вы использовали больше учётных записей (например, переключились на стратегию ротации).</p><h3 id="шаг-4-используите-«тренд-потребления-по-моделям-по-учетным-записям»-чтобы-поимать-аномальные-пики" tabindex="-1">Шаг 4: Используйте «тренд потребления по моделям/по учётным записям», чтобы поймать аномальные пики <a class="header-anchor" href="#шаг-4-используите-«тренд-потребления-по-моделям-по-учетным-записям»-чтобы-поимать-аномальные-пики" aria-label="Permalink to &quot;Шаг 4: Используйте «тренд потребления по моделям/по учётным записям», чтобы поймать аномальные пики&quot;">​</a></h3><p><strong>Почему</strong> Графики тренда — самый подходящий вход для поиска «внезапно подорожавших». Вам не нужно сначала знать причину, сначала выделите «какой день/какой час подорожел».</p><p>Действие:</p><ol><li>В правом верхнем углу графика переключитесь «По моделям / По учётным записям»</li><li>Наведите мышь (Tooltip) и обратите внимание на значение Top, сначала на那条 «внезапно вышедшую на первое место»</li></ol><p><strong>Вы должны увидеть</strong>:</p><ul><li>По моделям: какая-то модель внезапно поднялась в определённый период</li><li>По учётным записям: какая-то учётная запись внезапно поднялась в определённый период</li></ul><h3 id="шаг-5-используите-список-top-чтобы-«зафиксировать-самыи-дорогои-целевои-объект»" tabindex="-1">Шаг 5: Используйте список Top, чтобы «зафиксировать самый дорогой целевой объект» <a class="header-anchor" href="#шаг-5-используите-список-top-чтобы-«зафиксировать-самыи-дорогои-целевои-объект»" aria-label="Permalink to &quot;Шаг 5: Используйте список Top, чтобы «зафиксировать самый дорогой целевой объект»&quot;">​</a></h3><p><strong>Почему</strong> График тренда говорит вам «когда аномально», список Top говорит вам «кто самый дорогой». Перекрестив эти два, вы сможете быстро определить область устранения неполадок.</p><p>Действие:</p><ul><li>В представлении «По моделям» посмотрите на таблицу «подробная статистика по моделям<code>: </code>total_tokens / request_count / доля`</li><li>В представлении «По учётным записям» посмотрите на таблицу «подробная статистика по учётным записям»: <code>total_tokens / request_count</code></li></ul><p><strong>Вы должны увидеть</strong>: самые дорогие модели/учётные записи стоят спереди, а <code>request_count</code> может помочь вам различить «разово очень дорого» от «особенно много раз».</p><h3 id="шаг-6-необязательно-наидите-token-stats-db-чтобы-создать-резервную-копию-сверку" tabindex="-1">Шаг 6 (необязательно): Найдите <code>token_stats.db</code>, чтобы создать резервную копию/сверку <a class="header-anchor" href="#шаг-6-необязательно-наидите-token-stats-db-чтобы-создать-резервную-копию-сверку" aria-label="Permalink to &quot;Шаг 6 (необязательно): Найдите `token_stats.db`, чтобы создать резервную копию/сверку&quot;">​</a></h3><p><strong>Почему</strong> Когда вы подозреваете «отсутствие статистики» или хотите выполнить оффлайн-анализ, напрямую взять файл SQLite — самый надёжный.</p><p>Действие: перейдите в область Advanced в Settings и нажмите «Открыть каталог данных», вы найдете <code>token_stats.db</code> в каталоге данных.</p><p><strong>Вы должны увидеть</strong>: в списке файлов есть <code>token_stats.db</code> (имя файла жёстко задано на стороне бэкенда).</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><ul><li>Вы можете чётко сказать, что статистика Token Stats — это «извлечение из поля <code>usage</code>/<code>usageMetadata</code> в ответе, затем запись в локальный SQLite», а не облачное биллинг</li><li>Вы можете указать конкретный период времени пика в двух представлениях тренда «по моделям/по учётным записям»</li><li>Вы можете дать выполнимое заключение по устранению неполадок с помощью списка Top: сначала проверить, какая модель или учётная запись</li></ul><h2 id="напоминания-о-возможных-ошибках" tabindex="-1">Напоминания о возможных ошибках <a class="header-anchor" href="#напоминания-о-возможных-ошибках" aria-label="Permalink to &quot;Напоминания о возможных ошибках&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Явление</th><th>Частая причина</th><th>Что вы можете сделать</th></tr></thead><tbody><tr><td>Token Stats показывает «нет данных»</td><td>Вы действительно не генерировали запросы модели; или ответ вышестоящего провайдера не содержит разборимых полей токенов</td><td>Сначала отправьте запрос с уже подтверждённым клиентом; затем посмотрите, содержит ли ответ <code>usage/usageMetadata</code></td></tr><tr><td>Статистика «по моделям» выглядит неправильно</td><td>Статистика использует <code>model</code> запроса, а не <code>X-Mapped-Model</code></td><td>Считайте маршрутизацию моделей как «запрос модели → модель маршрутизации»; статистика смотрит на «запрос модели»</td></tr><tr><td>Отсутствует статистика по учётным записям</td><td>Только при получении <code>X-Account-Email</code> и разборе потребления токенов будет запись</td><td>Подтвердите, что запрос действительно прошёл через пул учётных записей; затем сравните с журналами запросов/заголовками ответа</td></tr><tr><td>После включения Proxy Monitor данные статистики завышены</td><td>Когда Proxy Monitor включён, токены каждого запроса будут записаны дважды</td><td>Это известная деталь реализации, не влияет на анализ относительного тренда; если нужно точное значение, временно отключите Monitor и протестируйте снова</td></tr></tbody></table><h2 id="краткое-содержание-урока" tabindex="-1">Краткое содержание урока <a class="header-anchor" href="#краткое-содержание-урока" aria-label="Permalink to &quot;Краткое содержание урока&quot;">​</a></h2><ul><li>Основная ценность Token Stats — это «количественное определение проблем затрат», сначала найти, затем оптимизировать</li><li>При записи необходимы учётная запись и потребление токенов; при отсутствии модели она будет записана как <code>&quot;unknown&quot;</code> (не блокирует запись)</li><li>Если вы хотите более точный контроль затрат, следующим шагом обычно вернуться к маршрутизации моделей или управлению квотами</li></ul><h2 id="предварительныи-просмотр-следующего-урока" tabindex="-1">Предварительный просмотр следующего урока <a class="header-anchor" href="#предварительныи-просмотр-следующего-урока" aria-label="Permalink to &quot;Предварительный просмотр следующего урока&quot;">​</a></h2><blockquote><p>Следующий урок мы решим «скрытые проблемы стабильности» в длинных сессиях: <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/advanced/context-compression/">Стабильность длинных сессий: Контекстное сжатие, кеширование подписей и сжатие результатов инструментов</a></strong>.</p></blockquote><p>Вам нужно узнать:</p><ul><li>Что делают три слоя прогрессивного сжатия контекста</li><li>Почему «кеширование подписей» может уменьшить ошибки подписи 400</li><li>Что будет удалено/сохранено при сжатии результатов инструментов</li></ul><hr><h2 id="приложение-ссылка-на-исходныи-код" tabindex="-1">Приложение: Ссылка на исходный код <a class="header-anchor" href="#приложение-ссылка-на-исходныи-код" aria-label="Permalink to &quot;Приложение: Ссылка на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть и просмотреть местоположение исходного кода</strong></summary><blockquote><p>Дата обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>UI Token Stats: переключение окна наблюдения/представления/получение данных</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L49-L166" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>49-166</td></tr><tr><td>UI Token Stats: подсказка «нет данных» (&quot;暂无数据&quot;)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L458-L507" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>458-507</td></tr><tr><td>Извлечение потребления токенов: разбор <code>model</code> из запроса, разбор <code>usage</code>/<code>usageMetadata</code> из ответа</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L32-L120" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>32-120</td></tr><tr><td>Извлечение потребления токенов: разбор поля <code>usage</code>/<code>usageMetadata</code> в потоке и в JSON</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L122-L336" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>122-336</td></tr><tr><td>Точка записи Token Stats: при получении учётной записи + токенов запись в SQLite</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L79-L136" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>79-136</td></tr><tr><td>Имя файла БД и структура таблицы: <code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>Логика записи: <code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>Логика запроса: часы/дни/недели, по учётным записям/по моделям, тренд и итоговый обзор</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>Команды Tauri: <code>get_token_stats_*</code> для фронтенда</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L791-L847" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>791-847</td></tr><tr><td>При запуске приложения инициализация БД Token Stats</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L50-L56" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>50-56</td></tr><tr><td>Страница Settings: получение/открытие каталога данных (для поиска <code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',59)])])}const g=e(d,[["render",l]]);export{b as __pageData,g as default};
